import sys
from collections import Counter

def solve_case(s):
    counts = Counter(s)
    for ch in s:
        if counts[ch] == 1:
            return ch
    return "NONE"

def main():
    data = sys.stdin.read().split()
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        out.append(solve_case(data[i]))
    sys.stdout.write("\n".join(out) + "\n")

main()
